// Unificar ambos triggers: webhook de Discord GUILD_MEMBER_ADD o ejecución manual (!onboarding @user)
const body = $json.body || $json || {};
const isWebhook = !!body.t; // Discord Gateway event has 't' field

let newMember = 'desconocido';
let discordUserId = null;
let isBot = false;

if (isWebhook) {
  // Discord GUILD_MEMBER_ADD via webhook/bot
  const d = body.d || body;
  const user = d.user || {};
  newMember = user.global_name || user.username || 'desconocido';
  discordUserId = user.id || null;
  isBot = user.bot === true;
} else {
  // Manual trigger desde !onboarding en Chat Discord
  newMember = body.new_member || body.usuario_target || body.actor || 'desconocido';
  discordUserId = body.discord_user_id || null;
  isBot = false;
}

if (isBot) {
  return [{ json: { skip: true, reason: 'Bot user, skip onboarding.' } }];
}

return [{ json: {
  correlation_id: `onboarding-${Date.now()}`,
  new_member: newMember,
  discord_user_id: discordUserId,
  skip: false,
  triggered_by: isWebhook ? 'discord_join' : 'manual'
}}];

const trigger = $('Normalize Trigger').item.json;
const pgRow = $('Fetch Project Context').item.json || {};
const safeArr = v => Array.isArray(v) ? v : [];
const safeObj = v => (v && typeof v === 'object' && !Array.isArray(v)) ? v : {};

const gfiBack = safeArr($('GitHub Good First Issues Backend').item.json);
const gfiFront = safeArr($('GitHub Good First Issues Frontend').item.json);

const kpis = safeObj(pgRow.kpis);
const github = safeObj(pgRow.github);
const fases = safeObj(pgRow.fases);
const ranking = safeArr(pgRow.ranking);
const hitos = safeArr(pgRow.hitos_proximos);
const primerasTareas = safeArr(pgRow.primeras_tareas_disponibles);
const alertasRecientes = safeArr(pgRow.alertas_recientes);

const progreso = Number(pgRow.progreso_pct || 0);
const diasFin = kpis.dias_hasta_fin || '?';
const velocidad = kpis.velocidad_tareas_por_dia || 0;
const newMember = trigger.new_member || 'Nuevo integrante';

// Good First Issues
const allGFI = [
  ...gfiBack.filter(i => !i.pull_request).map(i => ({ ...i, repo: 'Backend (NestJS)' })),
  ...gfiFront.filter(i => !i.pull_request).map(i => ({ ...i, repo: 'Frontend (Angular)' }))
].slice(0, 6);

const gfiStr = allGFI.length > 0
  ? allGFI.map(i => `• [${i.repo}] #${i.number} — ${i.title?.slice(0, 70)} (${i.html_url})`).join('\n')
  : '• No hay issues etiquetados como "good first issue" en este momento. Se asignará una tarea Trello disponible.';

// Tareas Trello disponibles para asignar
const tareasDisp = primerasTareas.length > 0
  ? primerasTareas.map(t => `• [${t.lista}] ${t.nombre}${t.vencimiento ? ' (vence: '+t.vencimiento.slice(0,10)+')' : ''}`).join('\n')
  : '• Sin tareas sin asignar disponibles en este momento.';

// Equipo actual
const equipoStr = ranking.slice(0, 5).map(r =>
  `• ${r.trello_name}: ${r.tareas_done} hechas, ${r.tareas_pending} pendientes`
).join('\n') || '(Sin datos de equipo disponibles)';

// Hitos próximos
const hitosStr = hitos.slice(0, 3).map(h => `• ${h.nombre} en ${h.dias_faltan}d`).join('\n') || '(Sin hitos próximos)';

// Alertas que debe conocer
const alertasStr = alertasRecientes.length > 0
  ? alertasRecientes.map(a => `• [${a.nivel?.toUpperCase()}] ${a.recomendacion?.slice(0,80)}`).join('\n')
  : 'Sin alertas activas.';

// Estado fases
const fasesStr = Object.values(fases).map(f =>
  `• ${f.nombre}: ${f.pct}% completado`
).join('\n') || '(Sin información de fases)';

const prompt = `Eres el PM Senior del proyecto PetSafe (software de gestión para clínica veterinaria, NestJS + Angular, cierre 10-jun-2026). Un nuevo integrante del equipo acaba de unirse: ${newMember}.

Tu tarea es crear un mensaje de bienvenida y onboarding personalizado, profesional, motivador y completo. Texto plano, SIN markdown, SIN asteriscos, en español.

ESTADO ACTUAL DEL PROYECTO:
Progreso: ${progreso}% (${pgRow.total_completadas}/${pgRow.total_tarjetas} funcionalidades)
Días hasta cierre: ${diasFin} | Velocidad actual: ${velocidad} entregas/día

FASES DEL PROYECTO:
${fasesStr}

PRÓXIMOS HITOS:
${hitosStr}

ALERTAS RECIENTES DEL SISTEMA:
${alertasStr}

Tu mensaje de bienvenida debe incluir:
1. BIENVENIDA: Saludo cálido y profesional a ${newMember}, menciona el proyecto y su importancia.
2. CONTEXTO DEL PROYECTO: Explica en 3-4 oraciones qué es PetSafe, el stack tecnológico (NestJS, Angular, PostgreSQL, n8n), y en qué fase están.
3. EL EQUIPO: Preséntale al equipo actual brevemente (FG=Felipe Guerrero, DM=David Mendez, DP=David Perez, JA=Josue Asencio). Menciona que puede preguntar cualquier duda.
4. PRIMERAS TAREAS RECOMENDADAS: Basándote en los issues y tareas disponibles, sugiere 2-3 con las que puede empezar.
5. CONVENCIONES IMPORTANTES: Menciona que deben usar commits convencionales (feat/fix/docs/chore), hacer PRs descriptivos y actualizar las tarjetas Trello.
6. RECURSOS CLAVE: Menciona que tiene acceso al bot PM (comandos: !ayuda, !kpis, !reporte, !estado, !ci) y puede pedir cualquier información del proyecto en cualquier momento.
7. PRIMER DIA: Qué debe hacer hoy (revisar tablero Trello, leer README, hacer un commit de prueba, presentarse en Discord).`;

const colorMap = { verde: 3066993, amarillo: 16761095, rojo: 15158332 };

return [{ json: {
  correlation_id: trigger.correlation_id,
  new_member: newMember,
  discord_user_id: trigger.discord_user_id,
  prompt,
  gfiStr,
  tareasDisp,
  equipoStr,
  hitosStr,
  alertasStr,
  progreso,
  diasFin
}}];

const raw = $json.text ?? $json.output ?? $json.response ?? '';
const welcomeText = typeof raw === 'string' ? raw.trim() : JSON.stringify(raw);
const ctx = $('Build Onboarding Context').item.json;

const memberMention = ctx.discord_user_id ? `<@${ctx.discord_user_id}>` : `**${ctx.new_member}**`;

// Split long welcome into chunks for Discord embed fields
const chunkText = (text, size = 900) => {
  const lines = String(text || '').split('\n');
  const chunks = [];
  let current = '';
  for (const line of lines) {
    if ((current + '\n' + line).length > size && current) { chunks.push(current); current = line; }
    else { current = current ? current + '\n' + line : line; }
  }
  if (current) chunks.push(current);
  return chunks.length ? chunks : ['(sin contenido)'];
};

const welcomeChunks = chunkText(welcomeText, 900);
const fields = [
  { name: '👋 Bienvenida', value: welcomeChunks[0].slice(0, 1024) }
];
if (welcomeChunks[1]) fields.push({ name: '📋 Continuación', value: welcomeChunks[1].slice(0, 1024) });
fields.push({ name: '🔰 Primeras Tareas Disponibles (Trello)', value: ctx.tareasDisp.slice(0, 800) });
fields.push({ name: '🐛 Good First Issues (GitHub)', value: ctx.gfiStr.slice(0, 800) });
fields.push({ name: '👥 El Equipo', value: ctx.equipoStr.slice(0, 500) });
fields.push({ name: '🤖 Comandos del Bot PM', value: '`!ayuda` · `!kpis` · `!reporte` · `!estado` · `!ci` · `!commits` · `!hitos` · `!riesgos` · `!acciones`' });

const discord_payload = {
  username: 'PM PetSafe · Onboarding',
  content: `👋 ¡Bienvenido al equipo PetSafe, ${memberMention}! Tu kit de onboarding está listo. 🚀`,
  embeds: [{
    title: `🎯 Kit de Onboarding · ${ctx.new_member}`,
    description: `El proyecto está al **${ctx.progreso}%** · **${ctx.diasFin} días** hasta el cierre el 10-jun-2026`,
    color: 5814783,
    fields: fields.slice(0, 8),
    footer: { text: 'Onboarding automático · PM PetSafe AI · Cualquier duda usa !ayuda en Discord' },
    timestamp: new Date().toISOString()
  }],
  allowed_mentions: { parse: ['users'] }
};

return [{ json: {
  correlation_id: ctx.correlation_id,
  agent_role: 'Team Onboarding',
  decision_type: 'onboarding',
  input_summary: `Onboarding: ${ctx.new_member}`.slice(0,500),
  context_used: { new_member: ctx.new_member, progreso: ctx.progreso },
  evidence: { welcome_text: welcomeText.slice(0,1000) },
  decision: { onboarded: ctx.new_member },
  recommendation: 'Onboarding completado. Verificar asignación de tareas en Trello.',
  confidence: 0.95,
  risk_level: 'low',
  requires_human_approval: false,
  discord_payload
}}];
